#include <stdio.h>
#include <stdlib.h>

static long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long g = gcd_ll(N - 1, M - 1);
        printf("%lld\n", g + 1);
    }
    return 0;
}

